('2-4-4-promotion:match:8a99b52e', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Promotion”?", "options": ["Informing customers about a product or service and persuading them to buy it.", "Offers available at the exact time and place of purchase, designed to tempt an immediate sale.", "The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media).", "A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items."]}'::jsonb, '{"answer": 0, "explain": "“Promotion” means: Informing customers about a product or service and persuading them to buy it."}'::jsonb),
('2-4-4-promotion:match:47da2219', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Point of Sale Promotion”?", "options": ["Offers available at the exact time and place of purchase, designed to tempt an immediate sale.", "The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media).", "A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items.", "Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it."]}'::jsonb, '{"answer": 0, "explain": "“Point of Sale Promotion” means: Offers available at the exact time and place of purchase, designed to tempt an immediate sale."}'::jsonb),
('2-4-4-promotion:match:2144e7ae', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Advertising Media”?", "options": ["A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items.", "The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media).", "Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it.", "Lowering the price of an item temporarily, often used to sell off old or seasonal stock."]}'::jsonb, '{"answer": 1, "explain": "“Advertising Media” means: The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media)."}'::jsonb),
('2-4-4-promotion:match:b466950f', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss Leader”?", "options": ["Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it.", "Lowering the price of an item temporarily, often used to sell off old or seasonal stock.", "Entering buyers into a draw to win a prize, which encourages repeat purchases.", "A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items."]}'::jsonb, '{"answer": 3, "explain": "“Loss Leader” means: A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items."}'::jsonb),
('2-4-4-promotion:match:3dda5569', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Free Sample”?", "options": ["Lowering the price of an item temporarily, often used to sell off old or seasonal stock.", "Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it.", "Entering buyers into a draw to win a prize, which encourages repeat purchases.", "An expensive media that reaches millions of people using high-impact moving images and sound."]}'::jsonb, '{"answer": 1, "explain": "“Free Sample” means: Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it."}'::jsonb),
