('2-4-4-promotion:match:5f0a23ef', '2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Television Advertising”?", "options": ["Advertising in physical formats like national/local newspapers and glossy magazines.", "An audio-only media that allows a business to target a specific geographical area cheaply.", "Digital platforms like Facebook and Instagram that allow highly targeted advertising to specific age groups and interests.", "An expensive media that reaches millions of people using high-impact moving images and sound."]}'::jsonb, '{"answer": 3, "explain": "“Television Advertising” means: An expensive media that reaches millions of people using high-impact moving images and sound."}'::jsonb),
