('2-4-5-place:match:b5af7f7c', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Place”?", "options": ["The movement of tangible goods from the producer to the consumer using transport.", "Delivering products electronically over the internet, such as streaming music or software.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The specific route a product takes from the manufacturer to the end-user."]}'::jsonb, '{"answer": 2, "explain": "“Place” means: The part of the marketing mix concerned with the distribution channels used to get goods to customers."}'::jsonb),
('2-4-5-place:match:492e0983', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Physical Distribution”?", "options": ["Delivering products electronically over the internet, such as streaming music or software.", "The specific route a product takes from the manufacturer to the end-user.", "The movement of tangible goods from the producer to the consumer using transport.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers."]}'::jsonb, '{"answer": 2, "explain": "“Physical Distribution” means: The movement of tangible goods from the producer to the consumer using transport."}'::jsonb),
('2-4-5-place:match:7e29b9ac', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Digital Distribution”?", "options": ["The specific route a product takes from the manufacturer to the end-user.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "Delivering products electronically over the internet, such as streaming music or software."]}'::jsonb, '{"answer": 3, "explain": "“Digital Distribution” means: Delivering products electronically over the internet, such as streaming music or software."}'::jsonb),
('2-4-5-place:match:c6cff139', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Distribution Channel”?", "options": ["A business that buys in massive bulk from producers and sells smaller quantities to retailers.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "The specific route a product takes from the manufacturer to the end-user.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public."]}'::jsonb, '{"answer": 2, "explain": "“Distribution Channel” means: The specific route a product takes from the manufacturer to the end-user."}'::jsonb),
('2-4-5-place:match:4b67fee1', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wholesaler”?", "options": ["The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Consumer. Cuts out all middlemen.", "A business that buys in massive bulk from producers and sells smaller quantities to retailers."]}'::jsonb, '{"answer": 3, "explain": "“Wholesaler” means: A business that buys in massive bulk from producers and sells smaller quantities to retailers."}'::jsonb),
('2-4-5-place:match:47657760', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Breaking Bulk”?", "options": ["A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Consumer. Cuts out all middlemen.", "The process of splitting massive factory shipments into smaller, affordable boxes for small shops.", "Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets."]}'::jsonb, '{"answer": 2, "explain": "“Breaking Bulk” means: The process of splitting massive factory shipments into smaller, affordable boxes for small shops."}'::jsonb),
('2-4-5-place:match:b6f60226', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retailer”?", "options": ["Producer → Consumer. Cuts out all middlemen.", "A business (like a supermarket or high-street shop) that sells goods directly to the general public.", "Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution."]}'::jsonb, '{"answer": 1, "explain": "“Retailer” means: A business (like a supermarket or high-street shop) that sells goods directly to the general public."}'::jsonb),
('2-4-5-place:match:ce6a8efa', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Direct Selling (Channel 1)”?", "options": ["Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "Producer → Consumer. Cuts out all middlemen.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally."]}'::jsonb, '{"answer": 1, "explain": "“Direct Selling (Channel 1)” means: Producer → Consumer. Cuts out all middlemen."}'::jsonb),
('2-4-5-place:match:fcc9b822', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Channel 2”?", "options": ["Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer."]}'::jsonb, '{"answer": 0, "explain": "“Channel 2” means: Producer → Retailer → Consumer. Often used by large brands selling to big supermarkets."}'::jsonb),
('2-4-5-place:match:f0c6a90b', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Piracy”?", "options": ["Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution.", "An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit."]}'::jsonb, '{"answer": 1, "explain": "“Piracy” means: The illegal copying and sharing of digital content, acting as a massive disadvantage to digital distribution."}'::jsonb),
('2-4-5-place:match:9bb1a13f', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “E-commerce”?", "options": ["An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit.", "Buying and selling goods over the internet, which allows businesses to operate 24/7 globally.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers."]}'::jsonb, '{"answer": 2, "explain": "“E-commerce” means: Buying and selling goods over the internet, which allows businesses to operate 24/7 globally."}'::jsonb),
('2-4-5-place:match:33727cb7', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Middleman”?", "options": ["An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer.", "A major cost for online clothing retailers when customers send back items that do not fit.", "The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The movement of tangible goods from the producer to the consumer using transport."]}'::jsonb, '{"answer": 0, "explain": "“Middleman” means: An intermediary (like a wholesaler or retailer) that sits between the producer and the consumer."}'::jsonb),
('2-4-5-place:match:bf0cc3e6', '2-4-5-place', '2.4.5 Place', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Return logistics”?", "options": ["The part of the marketing mix concerned with the distribution channels used to get goods to customers.", "The movement of tangible goods from the producer to the consumer using transport.", "A major cost for online clothing retailers when customers send back items that do not fit.", "Delivering products electronically over the internet, such as streaming music or software."]}'::jsonb, '{"answer": 2, "explain": "“Return logistics” means: A major cost for online clothing retailers when customers send back items that do not fit."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:c50de794', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Market data includes:", "options": ["changes in the school curriculum", "changes in market demand", "changes in the number of factory workers", "changes in workers'' hourly pay"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Market data relates to external consumer and competitor behaviors, such as demand, market share, and sales trends."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:118b5aea', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Which of the following will NOT normally be helped by the use of market data?", "options": ["Decisions on whether to increase production output", "Decisions on what questions to ask a candidate at a job interview", "Decisions on whether to build a new factory", "Decisions on whether to start a television advertising campaign"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Job interviews are a Human Resources function. Market data is used for Marketing and Operational planning."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:94a4c783', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Market share is best defined as:", "options": ["the product''s share of the total marketing mix budget", "the amount of goods a business sells in a 12-month period", "the amount of goods a business sells as a percentage of the total market for a product", "the goods that a business sells as a percentage of its previous year''s sales"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Market share measures how dominant a business is compared to ALL other competitors in that specific market combined."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:192489f4', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "PQS Ltd makes computer printers. The total market for the printers is 550,000 items per year. PQS Ltd sells 40,000 printers per year. What is PQS Ltd''s market share?", "options": ["7.27%", "8.21%", "8.79%", "9.14%"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Formula: (Business Sales / Total Market Sales) x 100. (40,000 / 550,000) x 100 = 7.27%."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:170dc8bc', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "What does it mean to have an ''Integrated Marketing Mix''?", "options": ["The business only focuses on Product and Price.", "The 4 Ps all complement each other and send a consistent message to the target market.", "The business spends an equal amount of money on all 4 Ps.", "The business integrates its marketing department with the HR department."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Integration means the parts fit together—e.g., a high-quality product is sold at a premium price, in an exclusive place, with high-end promotion."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:4537393e', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "A business launches a highly premium, luxury perfume. It prices it at £150 a bottle, but sells it only in a budget discount supermarket. This is an example of:", "options": ["Price skimming", "A poor integrated marketing mix", "Excellent use of market data", "Digital distribution"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The ''Place'' (a discount supermarket) heavily conflicts with the ''Product'' (luxury) and ''Price'' (£150), confusing the consumer and leading to failure."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:d12e5de2', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "How did Nintendo ensure its ''Promotion'' integrated perfectly with its ''Product'' for the Nintendo Switch?", "options": ["They advertised it as the cheapest console on the market.", "They focused all advertisements on the portability of the system within social settings.", "They offered a free game with every purchase.", "They only sold it through digital distribution."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The core Product innovation was portability; the Promotion highlighted this exactly, ensuring the mix was perfectly integrated."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:969dd719', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Company X sells 5,000 units in Year 1. In Year 2, Company X sells 6,000 units. However, their market share DROPPED. How is this mathematically possible?", "options": ["They increased their prices.", "The total market size grew faster than Company X''s sales grew.", "They spent less on advertising.", "It is mathematically impossible."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. If Company X grows by 20%, but competitors grow by 50%, Company X''s slice of the overall ''pie'' becomes smaller, meaning market share drops."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:809a6f8a', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "A target market is defined as:", "options": ["A supermarket where target goods are sold.", "The financial sales goal a business wishes to hit.", "The specific group of consumers to whom the business tries to sell its products.", "The percentage increase in the size of the total market."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Every element of the integrated marketing mix must be designed to appeal to this specific target group."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:247cdb18', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "If a business decides to use digital distribution (Place), how might this logically affect its Pricing strategy?", "options": ["Prices must always be higher because of website costs.", "Prices can potentially be lower because physical overhead costs (rent, delivery) are reduced.", "Prices must use price skimming.", "Digital distribution has absolutely no effect on Price."]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Because the 4 Ps are integrated, a change in Place (going digital = lower costs) allows the business flexibility to lower its Price."}'::jsonb),
('2-4-6-market-data-integrated-mix:mcq:172b2a7e', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'mcq', 'mcq', 1, '{"question": "Before taking drastic action (like stopping production) due to a sudden drop in sales shown in market data, a business should:", "options": ["Immediately fire the marketing team.", "Double the price of the product.", "View the data against a longer-term trend to see if it is just a temporary dip.", "Switch completely to digital distribution."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Short-term data can be misleading (e.g., a bad month due to a competitor''s brief sale). Long-term trends are required for major business decisions."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:baf854c5', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market data helps a business decide what questions to ask a candidate at a job interview."}'::jsonb, '{"answer": false, "explain": "FALSE. Market data is used for marketing and production decisions, not HR/recruitment processes."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:a9252856', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Market share is the amount of goods a business sells as a percentage of the total market for a product."}'::jsonb, '{"answer": true, "explain": "TRUE. It measures how much of the total market ''pie'' is controlled by one specific business."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:b5ed0ec7', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "If a company''s sales figures go up from one year to the next, their market share is guaranteed to go up as well."}'::jsonb, '{"answer": false, "explain": "FALSE. If the total market grows faster than the company''s sales (e.g., competitors are selling even more), the company''s market share will actually fall."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:d166fe7e', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "An integrated marketing mix means all 4 Ps work together and send a consistent message to the target market."}'::jsonb, '{"answer": true, "explain": "TRUE. The product, price, place, and promotion must all logically align. You cannot have a luxury price for a budget product in a discount store."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:b2bcc7fe', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "The Nintendo Switch used penetration pricing at launch because it was a cheap, basic console."}'::jsonb, '{"answer": false, "explain": "FALSE. Nintendo used Price Skimming (£279.99) because the Switch was a highly innovative, unique product."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:cb2eebb2', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "A poor marketing mix would be selling a highly priced luxury item on a basic, unsecure website."}'::jsonb, '{"answer": true, "explain": "TRUE. The premium Price and premium Product conflict directly with the poor-quality Place (distribution channel), which will deter customers."}'::jsonb),
('2-4-6-market-data-integrated-mix:tf:614ce0f1', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', 'tf', 'tf', 1, '{"question": "Using penetration pricing is a guaranteed way to make a large profit immediately."}'::jsonb, '{"answer": false, "explain": "FALSE. Penetration pricing involves setting artificially low prices. It sacrifices short-term profit to gain market share quickly."}'::jsonb)
